+        start: window[0].timestamp,
+        end: window[window.length - 1].timestamp
+      },
+      originalCount: window.length,
+      consolidated: result
+    });
+
+    console.log(`Window ${i + 1}: ${window.length} memories -> ${result.consolidatedCount} segments`);
