+        // Accumulate to output
+        for (let i = qStart; i < qEnd; i++) {
+          for (let j = kStart; j < kEnd; j++) {
+            const weight = blockWeights[(i - qStart) * (kEnd - kStart) + (j - kStart)];
+            for (let d = 0; d < dim; d++) {
+              output[i * dim + d] += weight * values[j * dim + d];
