+      this.flashConfig = { ...this.flashConfig, ...configs.flash };
+    }
+    if (configs.graphRoPE) {
+      this.graphRoPEConfig = { ...this.graphRoPEConfig, ...configs.graphRoPE };
+    }
+    if (configs.moe) {
+      this.moeConfig = { ...this.moeConfig, ...configs.moe };
+    }
+  }
